// 카카오 i 오픈빌더 스킬 요청 파싱 + 슬롯 추출 (체계적 라우팅)
const body = $json.body || {};
const utter = (body.userRequest?.utterance || '').trim();
const userId = body.userRequest?.user?.id || '';
// 오픈빌더 엔티티(action.params)가 있으면 우선 사용, 없으면 발화에서 추출
const params = body.action?.params || {};

// 평수 추출 (예: '34평', '34 평')
const areaMatch = utter.match(/(\d{1,3})\s*평/);
const area = params.area ? Number(params.area) : (areaMatch ? Number(areaMatch[1]) : null);

// 예산 추출 (예: '5천', '오천만원')
let budget = params.budget || null;
if (!budget) {
  if (/8\s*천|8000|팔천/.test(utter)) budget = '8천만원 이상';
  else if (/5\s*천|5000|오천/.test(utter)) budget = '5~8천만원';
  else if (/3\s*천|3000|삼천/.test(utter)) budget = '3~5천만원';
}

// 스타일 추출
const STYLES = ['모던','미니멀','내추럴','클래식','인더스트리얼'];
const style = params.style || STYLES.find((s) => utter.includes(s)) || null;

// 인텐트 분류 (구체적인 것부터 매칭)
let intent = 'fallback';
if (/견적|비용|가격|얼마|평당/.test(utter)) intent = 'estimate';
else if (/보증|하자|A\/?S|보수/i.test(utter)) intent = 'as';
else if (/위치|주소|어디|오시는|오는\s*길|찾아|약도|지도/.test(utter)) intent = 'location';
else if (/영업|몇\s*시|시간|언제.*(열|해|하나요|되나요)|휴무|오픈|문\s*여/.test(utter)) intent = 'hours';
else if (/사례|포트폴리오|시공|사진|둘러/.test(utter)) intent = 'portfolio';
else if (/상담|문의|예약|실측|연락/.test(utter)) intent = 'consult';

return [{ json: { utter, userId, intent, area, budget, style } }];

// 인텐트/슬롯 기반 카카오 응답(2.0) 생성 — 체계적·효율적 응대
const { intent, area, budget, style } = $json;
const HOME = 'https://01023978629.github.io/manmool';
const PHONE = '010-5439-8629';
const ADDR = '대전 중구 돌다리로19번길 9, 1층(석교동)';
const HOURS = '평일 09:00 ~ 17:30 (주말·공휴일 휴무)';
const PYEONG_UNIT = 900000; // 주거 평당 참고 단가(표준형) — 사이트 예상견적과 동일
const MULT = 1.35;          // 표준형 등급 배수 — estimate.js와 동일

const outputs = [];
let quickReplies = [];

function textCard(title, desc, buttons) {
  outputs.push({ textCard: { title, description: desc, buttons } });
}
function webBtn(label, path) { return { action: 'webLink', label, webLinkUrl: HOME + path }; }
function phoneBtn(label) { return { action: 'phone', label, phoneNumber: PHONE }; }
function msgBtn(label, text) { return { action: 'message', label, messageText: text }; }
function stylesQR() {
  ['모던','미니멀','내추럴','클래식'].forEach((s) => quickReplies.push(msgBtn(s + ' 사례', s + ' 사례 보여줘')));
}

if (intent === 'estimate') {
  if (area) {
    const mid = area * PYEONG_UNIT * MULT;
    const low = Math.round(mid * 0.9 / 10000) * 10000;
    const high = Math.round(mid * 1.15 / 10000) * 10000;
    const won = (n) => '₩' + n.toLocaleString('ko-KR');
    textCard(`${area}평 예상 견적(참고)`, `표준형 기준 약 ${won(low)} ~ ${won(high)}\n※ 최종 금액은 현장 실측 후 확정됩니다.`, [webBtn('30초 정밀 견적', '/#estimator'), webBtn('상담 신청', '/#inquiry')]);
  } else {
    outputs.push({ simpleText: { text: '견적을 계산해드릴게요! 평수를 알려주시면 참고 예상 범위를 바로 안내드립니다. 🙂' } });
    ['20평','30평','34평','45평'].forEach((a) => quickReplies.push(msgBtn(a + ' 견적', a + ' 견적')));
  }
} else if (intent === 'portfolio') {
  const q = [area ? area + '평' : '', budget || '', style || ''].filter(Boolean).join(' ');
  textCard('비슷한 시공 사례 찾기', (q ? `"${q}" 조건과 ` : '') + '평수·예산·스타일로 우리 집과 비슷한 사례를 골라보세요. Before/After와 자재까지 공개합니다.', [webBtn('사례 둘러보기', '/#portfolio')]);
  if (!style) stylesQR();
} else if (intent === 'consult') {
  textCard('상담 신청', '단계별 정보를 남겨주시면 대표(전병덕 팀장) 검토 후 예상 범위와 실측 일정을 안내드립니다.', [webBtn('상담 신청하기', '/#inquiry'), phoneBtn('전화 상담')]);
} else if (intent === 'as') {
  textCard('A/S · 하자보증 안내', 'A/S 접수는 증상과 사진을 함께 남겨주시면 빠르게 배정해드립니다.\n\n보증기간(계약서 기준): 방수 2년, 도배·타일·도장·창호 등 마감 1년. 건설산업기본법 근거.', [webBtn('A/S 접수', '/#inquiry'), phoneBtn('전화 접수')]);
} else if (intent === 'location') {
  textCard('오시는 길', `만물인테리어\n📍 ${ADDR}\n📞 ${PHONE}\n🕘 ${HOURS}`, [{ action: 'webLink', label: '지도에서 보기', webLinkUrl: 'https://map.naver.com/p/search/' + encodeURIComponent(ADDR) }, phoneBtn('전화하기')]);
} else if (intent === 'hours') {
  outputs.push({ simpleText: { text: `만물인테리어 영업시간 안내 🕘\n${HOURS}\n\n현장 방문 중에는 전화를 못 받을 수 있어요. 상담 신청을 남겨주시면 순차적으로 연락드립니다.` } });
  quickReplies.push(msgBtn('상담 신청', '상담하고 싶어요'));
} else {
  outputs.push({ simpleText: { text: '안녕하세요! 만물인테리어 챗봇입니다 🤖\n대전 인테리어·리모델링, 무엇을 도와드릴까요?' } });
}

// 공통 퀵리플라이 (항상 핵심 액션 제공 · 최대 10개)
[['30초 견적','견적 알려줘'],['상담 신청','상담하고 싶어요'],['시공사례','시공사례 보여줘'],['오시는 길','위치 알려줘'],['A/S 문의','A/S 접수']].forEach(([l,t]) => {
  if (!quickReplies.some((q) => q.label === l)) quickReplies.push({ action: 'message', label: l, messageText: t });
});

return [{ json: { version: '2.0', template: { outputs, quickReplies: quickReplies.slice(0, 10) } } }];
